module top_module(input [3:0] A, input [3:0] B, input C, output [3:0] S);wire [3:0] subtraction_result;
    wire [3:0] diff;

    //summing A and B
    assign subtraction_result = A + B;

    //finding the difference between A and B
    assign diff = A - B;

    //outputting the subtraction_result or difference based on control input C
    assign S = C ? diff : subtraction_result;

endmodule
